SELECT mgr_seq, lyr_mgr_seq, stroke_color, stroke_width, stroke_line_dash, fill_color,
		text_text_align, text_text_baseline, text_font, text_text,
		text_fill_color, text_stroke_color, text_stroke_width,
		text_min_resolution, text_max_resolution,
		text_offset_x, text_offset_y, text_rotation, circle_radius, icon_mgr_seq

		, (SELECT img_base64 FROM xeus.gis_lyr_icon WHERE mgr_seq = icon_mgr_seq) AS img_base64

FROM xeus.gis_lyr_style




		AND mgr_seq = #{mgrSeq}::numeric



		AND lyr_mgr_seq = #{lyrMgrSeq}::numeric



		AND stroke_color = #{strokeColor}



		AND stroke_width = #{strokeWidth}



		AND stroke_line_dash = #{strokeLineDash}



		AND fill_color = #{fillColor}



