		AND text_offset_x = #{textOffsetX}::numeric



		AND text_offset_y = #{textOffsetY}::numeric



		AND text_rotation = #{textRotation}::numeric



		AND circle_radius = #{circleRadius}::numeric



		AND icon_mgr_seq = #{iconMgrSeq}::numeric






